          '6': { text: 'Susun vokal dan konsonan secara bergantian:\nA _ I _ U\nApa yang mengisi tempat kosong pertama?', options: ['B', 'E', 'O', 'N'] },
          '7': { text: 'Deret ini bergantian genap, ganjil, genap, ganjil...:\n4, 7, 2, 9, 6, ___', options: ['8', '3', '10', '11'] },
          '8': { text: 'Bergantian hewan dan buah: anjing, apel, kucing, pisang, burung, ___', options: ['ceri', 'ikan', 'gajah', 'anggur'] },
          '9': { text: 'Elemen ke-8 dari urutan bergantian ini?\nMerah, Biru, Merah, Biru...', options: ['Merah', 'Biru', 'Merah atau Biru', 'Tidak keduanya'] },
          '10': { text: 'Dalam deret A1B2C3D4, pasangan huruf-angka setelah "C3" adalah?', options: ['E5', 'D4', 'D5', 'E4'] },
