          '12': { text: 'Bergantian tambah 3 dan kurang 1:\nMulai dari 10. Terapkan: +3, −1, +3, −1. Hasilnya?', options: ['14', '16', '18', '12'] },
          '13': { text: 'Mengikuti aturan "angka, huruf, angka, huruf", urutan yang benar adalah?', options: ['1A2B', '1A23', 'AB12', '1234'] },
          '14': { text: 'Elemen ke-12 dari deret 1, A, 2, B, 3, C, 4, D, 5, E, 6, ___ adalah?', options: ['F', '7', 'G', '6'] },
          '15': { text: 'Dalam deret 2, 4, 3, 6, 4, 8, 5, ___, angka selanjutnya adalah?', options: ['6', '9', '10', '7'] },
          '16': { text: 'Jika Januari = 1, Februari = 2, dst., berapa Maret + Juli + November?', options: ['18', '19', '21', '22'] },
          '17': { text: 'Balikkan urutan kata-kata ini: "kucing duduk tikar"\nHasilnya?', options: ['tikar duduk kucing', 'duduk kucing tikar', 'kucing tikar duduk', 'tikar kucing duduk'] },
