          '7': { text: 'Hitung hanya vokal dalam "Tes Stroop".\nBerapa jumlah vokal?', options: ['2', '3', '4', '5'] },
          '8': { text: 'Hitung berapa kali huruf "a" muncul dalam kalimat:\n"Ayah dan adik asyik bermain bersama anak-anak"', options: ['5', '6', '7', '8'] },
          '9': { text: 'Dalam daftar ini, kata mana yang tidak memiliki huruf ganda?\nALLAH, AGAMA, TAAT, EMAS', options: ['ALLAH', 'AGAMA', 'TAAT', 'EMAS'] },
          '10': { text: 'Baca kalimat ini dan hitung hanya kata warna:\n"Mobil biru melewati gudang merah di samping ladang hijau."\nBerapa kata warna?', options: ['2', '3', '4', '1'] },
          '11': { text: 'Abaikan yang jelas:\nSatu kilogram bulu dan satu kilogram batu bata, mana yang lebih berat?', options: ['Batu bata', 'Bulu', 'Beratnya sama', 'Tergantung kepadatan'] },
          '12': { text: 'Seorang petani punya 17 domba. Semua kecuali 9 mati. Berapa domba yang tersisa?', options: ['8', '9', '17', '0'] },
          '13': { text: 'Berapa bulan yang memiliki 28 hari?', options: ['1', '2', '4', '12'] },
          '14': { text: 'Seekor ayam jantan bertelur di atas atap gudang. Ke arah mana telur menggelinding?', options: ['Timur', 'Barat', 'Menuruni lereng', 'Ayam jantan tidak bertelur'] },
          '15': { text: 'Anda di ruangan gelap dengan lilin, tungku kayu, dan lampu gas. Anda punya satu korek. Apa yang Anda nyalakan pertama?', options: ['Lilin', 'Tungku kayu', 'Lampu gas', 'Korek'] },
          '16': { text: 'Kata "PANJANG" ada di sebelah garis pendek. Kata "PENDEK" ada di sebelah garis panjang. Garis mana yang lebih panjang?', options: ['Yang di sebelah "PANJANG"', 'Yang di sebelah "PENDEK"', 'Sama panjang', 'Tidak dapat ditentukan dari deskripsi'] },
          '17': { text: 'Kata "UTARA" ditampilkan menunjuk ke selatan di kompas. Arah mana yang sebenarnya ditunjuk panah?', options: ['Utara', 'Timur', 'Selatan', 'Barat'] },
          '18': { text: '"SALAH" adalah jawaban yang benar untuk pertanyaan ini. Apa jawaban yang benar?', options: ['BENAR', 'SALAH', 'TIDAK TEPAT', 'TIDAK ADA'] },
          '19': { text: 'Dalam deret 1, 2, 1, 2, 1... jika dikatakan angka ke-10 adalah 1, apakah benar?', options: ['Ya', 'Tidak', 'Tidak dapat ditentukan', 'Hanya di posisi ganjil'] },
