          '21': { text: 'Berapa huruf dalam kata "salah" yang berada di posisi yang benar menurut urutan abjad?', options: ['Ini pertanyaan jebakan — menanyakan tentang kata itu sendiri', 'Tidak — ini jebakan', '3', 'Jawabannya — kata itu sendiri dieja dengan benar'] },
          '22': { text: 'Kalimat mana yang merujuk pada dirinya sendiri?', options: ['"Kalimat ini terdiri dari lima kata."', '"Langit itu biru."', '"Anjing adalah hewan."', '"Ikan berenang di laut."'] },
          '23': { text: 'Jika kebalikan hitam adalah putih, kebalikan atas adalah bawah, maka kebalikan "salah" adalah ___?', options: ['Kiri', 'Kanan', 'Benar', 'Salah'] },
          '24': { text: 'Baca hanya huruf pertama setiap kata dari kiri ke kanan:\n"Budi Anak Guru Umar Sederhana"', options: ['BAGUS', 'BAGUS', 'ABGUS', 'BGAUS'] },
